/**
 * @param {Record<string, unknown>} stateObject
 */
const computeDataAndesState = (stateObject) => {
  const datasetValue = Object.entries(stateObject).reduce((acc, [key, value]) => {
    if (key === 'otherDataAndesState') {
      const otherStates = (/** @type {string} */ (value)).split(' ');
      otherStates.forEach((state) => {
        acc.push(state);
      });
    } else if (value) {
      acc.push(key);
    }

    return acc;
  }, /** @type {string[]} */ ([]));

  return {
    'data-andes-state': datasetValue.join(' ') || undefined,
  };
};

export { computeDataAndesState };
